/* Simplified pseudocode for a router deciding which shard to query */

function shardFor(key) {
  // metadata_map is an in-memory cache of key-range -> shard
  range = binarySearch(metadata_map, key)
  return range.shard
}

function executeQuery(logicalTable, key, sql, params) {
  shard = shardFor(key)
  physicalDB = connect(shard.endpoint)
  // Use prepared statements, retries with idempotency where safe
  return physicalDB.execute(sql, params)
}

/* Example: moving a key-range in a migration controller */

1) Mark range as 'copying' in metadata
2) Start background copy from old_shard -> new_shard using consistent snapshot
3) Verify checksum and lag
4) Update metadata atomically to point range -> new_shard
5) Finish and cleanup old_shard data

