/* Orchestrator pseudo-code with persisted saga state (Node.js-like) */

class SagaOrchestrator {
  async start(orderId) {
    await sagaStore.create({ orderId, state: 'STARTED' });
    try {
      await this.stepCharge(orderId);
      await this.stepReserveFlight(orderId);
      await this.stepReserveHotel(orderId);
      await sagaStore.update(orderId, { state: 'COMPLETED' });
    } catch (err) {
      await this.compensate(orderId);
      await sagaStore.update(orderId, { state: 'FAILED', reason: err.message });
    }
  }

  // each step records progress, so we can resume/retry
  async stepCharge(orderId) { /* call Payment, record progress */ }
  async stepReserveFlight(orderId) { /* call Flight, record progress */ }
  async stepReserveHotel(orderId) { /* call Hotel, record progress */ }

  async compensate(orderId) {
    // read saga progress and run compensations in reverse order
  }
}
